Method.Source:
/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    WHSLicensePlateLabel    wHSLicensePlateLabel;
   ttsbegin;
    while select forupdate wHSLicensePlateLabel
        where wHSLicensePlateLabel.WorkTransType == WHSWorkTransType::ProdPut
           && !wHSLicensePlateLabel.ItemId
           && !wHSLicensePlateLabel.OrderNum
    {
        wHSLicensePlateLabel.doDelete();
    }
    ttscommit;
}
